package com.sme.erp.accounting.controller; import com.sme.erp.accounting.dto.FinancialDashboardDTO; import com.sme.erp.accounting.service.FinancialDashboardService; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/accounting/financial-dashboard") public class FinancialDashboardController {private final FinancialDashboardService service;public FinancialDashboardController(FinancialDashboardService s){service=s;}@GetMapping @PreAuthorize("hasAuthority('FINANCIAL_DASHBOARD_VIEW')") public FinancialDashboardDTO get(@RequestParam(required=false)Integer fiscalYear){return service.get(fiscalYear);}}
